_call_log = {}


def rate_limit(max_calls, window=60):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            key = func.__name__
            now = time.time()
            calls = _call_log.get(key, [])
            calls = [t for t in calls if now - t < window]
            if len(calls) >= max_calls:
